"use client";

import {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
  useRef,
  type ReactNode,
} from "react";
import { setMuted as _setMuted } from "@/lib/sounds";
import { playClick } from "@/lib/sounds";

const SOUNDS_KEY = "math-haohao-wan-sounds-on";
const TIP_DISMISSED_KEY = "math-haohao-wan-sound-tip-dismissed";

const SoundCtx = createContext<{ muted: boolean; toggle: () => void }>({
  muted: true,
  toggle: () => {},
});

export function useSound() {
  return useContext(SoundCtx);
}

export default function SoundProvider({ children }: { children: ReactNode }) {
  const [muted, setMutedState] = useState(false); // 默认开启音效
  const [showTip, setShowTip] = useState(false);
  const tipTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    // 读取用户之前的偏好
    try {
      const saved = localStorage.getItem(SOUNDS_KEY);
      const on = saved !== null ? saved === "true" : true; // 默认开启
      setMutedState(!on);
      _setMuted(!on);

      // 首次访问且音效关闭时，延迟显示提示
      if (!saved) {
        tipTimerRef.current = setTimeout(() => setShowTip(true), 2000);
      }
    } catch {
      // ignore
    }
    return () => {
      if (tipTimerRef.current) clearTimeout(tipTimerRef.current);
    };
  }, []);

  const toggle = useCallback(() => {
    setMutedState((prev) => {
      const next = !prev;
      _setMuted(next);
      if (!next) {
        // 开启时播放一个示例音效
        playClick();
      }
      try {
        localStorage.setItem(SOUNDS_KEY, String(!next));
      } catch {
        // ignore
      }
      return next;
    });
    setShowTip(false);
    try {
      localStorage.setItem(TIP_DISMISSED_KEY, "true");
    } catch {
      // ignore
    }
  }, []);

  const dismissTip = useCallback(() => {
    setShowTip(false);
    try {
      localStorage.setItem(TIP_DISMISSED_KEY, "true");
    } catch {
      // ignore
    }
  }, []);

  return (
    <SoundCtx.Provider value={{ muted, toggle }}>
      {children}

      {/* 音效提示气泡 — 首次进入时显示 */}
      {showTip && (
        <div
          className="fixed bottom-20 right-4 z-50 animate-float-in flex items-center gap-2 rounded-[var(--radius-sm)] border border-[var(--border)] bg-[var(--bg-card)] px-4 py-3 shadow-[var(--shadow-md)]"
          style={{ maxWidth: 200 }}
        >
          <span className="text-lg">🔊</span>
          <span className="text-sm text-[var(--text-secondary)]">
            点击开启音效，学习更有趣！
          </span>
          <button
            onClick={dismissTip}
            className="ml-1 flex h-5 w-5 flex-shrink-0 items-center justify-center rounded-full text-[var(--text-muted)] hover:bg-[var(--bg-soft)] text-xs"
          >
            ✕
          </button>
        </div>
      )}

      {/* 全局音效开关按钮 — 更醒目 */}
      <button
        onClick={toggle}
        className={`fixed bottom-4 right-4 z-50 flex h-14 w-14 items-center justify-center rounded-full shadow-[var(--shadow-lg)] border-2 transition-all hover:scale-110 active:scale-95 ${
          muted
            ? "bg-[var(--bg-card)] border-[var(--border)]"
            : "bg-[var(--primary)] border-[var(--primary-dark)]"
        }`}
        title={muted ? "开启音效" : "关闭音效"}
        aria-label={muted ? "开启音效" : "关闭音效"}
      >
        {muted ? (
          <span className="text-2xl opacity-40">🔇</span>
        ) : (
          <span className="text-2xl">🔊</span>
        )}
      </button>
    </SoundCtx.Provider>
  );
}
