// ===== 音效引擎 =====
// 使用 Web Audio API 程序化生成音效，无需外部音频文件
// 音色设计：温暖、轻快、适合小学生

let audioCtx: AudioContext | null = null;

function getCtx(): AudioContext | null {
  if (typeof window === "undefined") return null;
  if (!audioCtx) {
    audioCtx = new (window.AudioContext || (window as unknown as { webkitAudioContext: typeof AudioContext }).webkitAudioContext)();
  }
  return audioCtx;
}

let muted = false;
export function setMuted(m: boolean) {
  muted = m;
}

export function isMuted(): boolean {
  return muted;
}

/** 播放一个简单的正弦波音符 */
function playTone(freq: number, duration: number, volume = 0.15, type: OscillatorType = "sine", delay = 0) {
  const ctx = getCtx();
  if (!ctx || muted) return;

  const osc = ctx.createOscillator();
  const gain = ctx.createGain();
  osc.type = type;
  osc.frequency.setValueAtTime(freq, ctx.currentTime + delay);
  gain.gain.setValueAtTime(volume, ctx.currentTime + delay);
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + delay + duration);
  osc.connect(gain);
  gain.connect(ctx.destination);
  osc.start(ctx.currentTime + delay);
  osc.stop(ctx.currentTime + delay + duration);
}

// ===== 音效库 =====

/** 点击 / 按钮音效 — 轻柔的"嘀" */
export function playClick() {
  playTone(880, 0.08, 0.1, "sine");
}

/** 成功音效 — 上行三音和弦 C-E-G */
export function playSuccess() {
  playTone(523.25, 0.15, 0.12, "sine", 0);     // C5
  playTone(659.25, 0.15, 0.10, "sine", 0.08);   // E5
  playTone(783.99, 0.2, 0.10, "sine", 0.16);    // G5
}

/** 完成 / 庆祝音效 — C-E-G-C 上行琶音 */
export function playCelebrate() {
  playTone(523.25, 0.18, 0.12, "sine", 0);      // C5
  playTone(659.25, 0.18, 0.12, "sine", 0.1);    // E5
  playTone(783.99, 0.18, 0.12, "sine", 0.2);    // G5
  playTone(1046.50, 0.35, 0.14, "sine", 0.3);   // C6
}

/** 抖动 / 提示音效 — 低频短促的"嗡" */
export function playShake() {
  const ctx = getCtx();
  if (!ctx || muted) return;
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();
  osc.type = "triangle";
  osc.frequency.setValueAtTime(220, ctx.currentTime);
  osc.frequency.exponentialRampToValueAtTime(150, ctx.currentTime + 0.15);
  gain.gain.setValueAtTime(0.12, ctx.currentTime);
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.15);
  osc.connect(gain);
  gain.connect(ctx.destination);
  osc.start();
  osc.stop(ctx.currentTime + 0.15);
}

/** 翻转音效 — 上升的滑音 */
export function playFlip() {
  const ctx = getCtx();
  if (!ctx || muted) return;
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();
  osc.type = "sine";
  osc.frequency.setValueAtTime(400, ctx.currentTime);
  osc.frequency.exponentialRampToValueAtTime(800, ctx.currentTime + 0.15);
  gain.gain.setValueAtTime(0.1, ctx.currentTime);
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 0.18);
  osc.connect(gain);
  gain.connect(ctx.destination);
  osc.start();
  osc.stop(ctx.currentTime + 0.18);
}

/** 拖拽 / 放置音效 — 短促的"咔" */
export function playDrop() {
  playTone(600, 0.06, 0.1, "square");
}

/** 步骤推进音效 — 轻柔的上行双音 */
export function playStep() {
  playTone(440, 0.1, 0.08, "sine", 0);
  playTone(554.37, 0.12, 0.08, "sine", 0.06);
}

/** 发现 / 星星音效 — 闪烁感的三连音 */
export function playDiscover() {
  playTone(783.99, 0.12, 0.08, "sine", 0);
  playTone(987.77, 0.12, 0.08, "sine", 0.1);
  playTone(1174.66, 0.25, 0.10, "sine", 0.2);
}
